다음 C 프로그램의 출력 결과는?

```c
#include <stdio.h>
int main() {
    int arr[5] = {3, 1, 4, 1, 5};
    int *p = arr;
    int sum = 0;
    for (int i = 0; i < 5; i++) {
        sum += *(p + i);
    }
    printf("%d", sum);
    return 0;
}
```

다음 파이썬 프로그램의 출력 결과는?

```python
def func(n):
    if n <= 1:
        return 1
    return n * func(n - 1)

print(func(5))
```

다음 C 프로그램의 출력 결과는?

```c
#include <stdio.h>
int main() {
    int a = 5, b = 3;
    int *p = &a, *q = &b;
    *p = *p + *q;
    *q = *p - *q;
    *p = *p - *q;
    printf("%d %d", a, b);
    return 0;
}
```
